#!/usr/bin/env python3
"""
Hace mas transparentes las cards de servicio del portal publico en tema oscuro
(menos blur, menos tinte blanco) para que se vea el fondo azul con luces detras,
en vez de un azul solido.

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_portal_card_transparency.py
"""

import base64
from pathlib import Path

PORTAL_CSS_B64 = """"""

def main():
    p = Path("src/components/portal.css")
    p.write_bytes(base64.b64decode(PORTAL_CSS_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Cards del portal mas transparentes en tema oscuro'")
    print("  git push")

if __name__ == "__main__":
    main()